+    fn txn_metrics_map(rows: &[Row]) -> HashMap<String, i64> {
+        rows.iter()
+            .filter_map(|row| {
+                let name = match row.values().first() {
+                    Some(SqliteValue::Text(name)) => name.clone(),
+                    _ => return None,
+                };
+                let value = match row.values().get(1) {
+                    Some(SqliteValue::Integer(value)) => *value,
+                    _ => return None,
+                };
+                Some((name, value))
+            })
+            .collect()
+    }
